4	// Sessions has been merged into the layer-aware Runs row expansion.
5	// Client-side navigations land here and are 302-redirected to /runs?layer=run.
6	// Direct/bookmarked URLs are also redirected (with a Sunset header) by the
7	// Go server (see cli/internal/server/server.go).
8	export const load: PageLoad = ({ params, url }) => {
9		const search = new URLSearchParams(url.search);
10		search.set('layer', 'run');
11		const target = `/nodes/${params.nodeId}/projects/${params.projectId}/runs?${search.toString()}`;
12		throw redirect(302, target);
13	};
