84	function sessionsPayload(rows: SessionNode[]) {
85		const cashUsd = rows
86			.filter((row) => row.billingMode === 'paid')
87			.reduce((sum, row) => sum + (row.cost ?? 0), 0);
88		const subscriptionEquivUsd = rows
89			.filter((row) => row.billingMode === 'subscription')
90			.reduce((sum, row) => sum + (row.cost ?? 0), 0);
91		const localRows = rows.filter((row) => row.billingMode === 'local');
92		return {
93			agentSessions: {
94				edges: rows.map((node) => ({ node, cursor: node.id })),
95				pageInfo: { hasNextPage: false, endCursor: null },
96				totalCount: rows.length
97			},
98			sessionsCostSummary: {
99				cashUsd,
100				subscriptionEquivUsd,
101				localSessionCount: localRows.length,
102				localEstimatedUsd: null
103			}
104		};
105	}
