130	test.describe('DDx Server UI Screenshots', () => {
131		for (const mode of MODES) {
132			for (const pg of PAGES) {
133				test(`${pg.name} (${mode})`, async ({ page, request }) => {
134					const ids = await getFixtureIds(request);
135	
136					await page.addInitScript((m) => {
137						window.localStorage.setItem('mode-watcher-mode', m);
138					}, mode);
139	
