import { expect, test } from '@playwright/test';

// Sessions have moved into the layer-aware Runs row expansion. The standalone
// /sessions route now 302-redirects to /runs?layer=run, and run-layer rows
// expand to show the session detail tabs (Overview / Prompt / Response /
// Session / Tools / Evidence) inline in the Runs table.

const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
const PROJECT_ID = 'proj-1';
const PROJECTS = [{ id: PROJECT_ID, name: 'Project Alpha', path: '/repos/alpha' }];
const SESSIONS_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/sessions`;
const RUNS_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/runs?layer=run`;

const RUN_ID = 'run-run-001';
const BEAD_ID = 'ddx-runs-test';

const runListRow = {
	id: RUN_ID,
	layer: 'run',
	status: 'success',
	projectID: PROJECT_ID,
	beadId: BEAD_ID,
	startedAt: '2026-04-30T10:06:00Z',
	durationMs: 720_000,
	harness: 'claude',
	queueInputs: null
};

const runDetail = {
	id: RUN_ID,
	layer: 'run',
	status: 'success',
	projectID: PROJECT_ID,
	beadId: BEAD_ID,
	artifactId: null,
	parentRunId: null,
	childRunIds: [],
	startedAt: '2026-04-30T10:06:00Z',
	completedAt: '2026-04-30T10:18:00Z',
	durationMs: 720_000,
	queueInputs: null,
	stopCondition: null,
	selectedBeadIds: null,
	baseRevision: null,
	resultRevision: null,
	worktreePath: null,
	mergeOutcome: null,
	checkResults: null,
	harness: 'claude',
	provider: 'anthropic',
	model: 'claude-sonnet-4-6',
	promptSummary: 'execute bead test',
	powerMin: 2,
	powerMax: 4,
	tokensIn: 12000,
	tokensOut: 3400,
	costUsd: 0.0876,
	outputExcerpt: 'completed with success',
	evidenceLinks: null,
	prompt: 'run-layer prompt body',
	response: 'run-layer response body',
	stderr: null,
	billingMode: 'paid',
	outcome: 'success',
	detail: null,
	cachedTokens: 200
};

const sessionDetail = {
	id: RUN_ID,
	workerId: 'worker-session-owner',
	harness: 'claude',
	model: 'claude-sonnet-4-6',
	cost: 0.0876,
	billingMode: 'paid',
	baseRev: null,
	resultRev: null,
	stdoutPath: null,
	stderrPath: null,
	tokens: { prompt: 12000, completion: 3400, total: 15400, cached: 200 },
	status: 'completed',
	outcome: 'success',
	prompt: 'session prompt body',
	response: 'session response body',
	stderr: null
};

async function installGraphQLRoutes(page: import('@playwright/test').Page) {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as {
			query: string;
			variables?: Record<string, unknown>;
		};
		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
			return;
		}
		if (body.query.includes('ProjectsForLayout') || body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: PROJECTS.map((node) => ({ node })) } }
				})
			});
			return;
		}
		if (body.query.includes('ProjectRuns')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						runs: {
							edges: [{ node: runListRow, cursor: RUN_ID }],
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: 1
						}
					}
				})
			});
			return;
		}
		if (
			body.query.includes('RunHeader') ||
			body.query.includes('RunDetailExpand') ||
			body.query.includes('RunDetail') ||
			body.query.includes('RunExists')
		) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: runDetail } })
			});
			return;
		}
		if (body.query.includes('RunSessionExpand')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { agentSession: sessionDetail } })
			});
			return;
		}
		if (body.query.includes('ParentRunParent')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: null } })
			});
			return;
		}
		if (body.query.includes('RunExecutionExpand')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { execution: null } })
			});
			return;
		}
		if (body.query.includes('RunToolCallsExpand')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						runToolCalls: {
							edges: [],
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: 0
						}
					}
				})
			});
			return;
		}
		if (body.query.includes('RunEvidenceFiles')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: { id: RUN_ID, bundleFiles: [] } } })
			});
			return;
		}
		if (body.query.includes('ProducedArtifact')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { artifact: null } })
			});
			return;
		}
		await route.continue();
	});
}

test('sessions URL redirects into the run-layer view of runs', async ({ page }) => {
	await installGraphQLRoutes(page);

	await page.goto(SESSIONS_URL);

	// The /sessions route 302-redirects to /runs?layer=run; the runs page
	// renders with the layer=run filter active.
	await expect(page).toHaveURL(/\/runs\?.*\blayer=run\b/);
	await expect(page.getByRole('heading', { name: 'Runs' })).toBeVisible();
	await expect(page.getByTestId('layer-chip-run')).toHaveAttribute('aria-pressed', 'true');

	// Direct visit to /runs?layer=run shows the same view.
	await page.goto(RUNS_URL);
	await expect(page.getByRole('heading', { name: 'Runs' })).toBeVisible();
	await expect(page.getByRole('row', { name: new RegExp(`run.*${BEAD_ID}`, 'i') })).toBeVisible();
});

test('run-layer row expansion surfaces session detail tabs', async ({ page }) => {
	await installGraphQLRoutes(page);

	await page.goto(RUNS_URL);

	const row = page.locator(`tr[data-run-row="${RUN_ID}"]`);
	await expect(row).toBeVisible();
	await row.click();

	const detail = page.locator('[data-testid="rundetail"][data-layer="run"]');
	await expect(detail).toBeVisible();
	await expect(detail.locator('button[data-tab="overview"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="prompt"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="response"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="session"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="tools"]')).toBeVisible();
	await expect(detail.locator('button[data-tab="evidence"]')).toBeVisible();

	await detail.locator('button[data-tab="prompt"]').click();
	await expect(detail.locator('[data-testid="rundetail-prompt-body"]')).toContainText(
		'session prompt body'
	);

	await detail.locator('button[data-tab="response"]').click();
	await expect(detail.locator('[data-testid="rundetail-response-body"]')).toContainText(
		'session response body'
	);
});

